/// Render an icon as SVG elements within a given bounding box.
/// Returns SVG path element(s) for the icon.
pub fn render_icon_svg(
    name: &str,
    x: f32,
    y: f32,
    size: f32,
    fill: &str,
) -> String {
    if let Some((vw, vh, path_d)) = lookup_icon(name) {
        let scale = size / vw.max(vh);
        let tx = x + (size - vw * scale) / 2.0;
        let ty = y + (size - vh * scale) / 2.0;
        format!(
            "<g transform=\"translate({tx:.2},{ty:.2}) scale({scale:.6})\"><path d=\"{path_d}\" fill=\"{fill}\"/></g>"
        )
    } else {
        // Fallback: render the icon name as text
        let cx = x + size / 2.0;
        let cy = y + size / 2.0;
        let fs = size * 0.4;
        format!(
            "<text x=\"{cx:.2}\" y=\"{cy:.2}\" text-anchor=\"middle\" dominant-baseline=\"middle\" font-size=\"{fs:.1}\" fill=\"{fill}\">{name}</text>"
        )
    }
}
